import './App.css';
import { Link, Route, Routes } from 'react-router-dom';
import Home from './components/side _nav/side_nav';
import About from './components/Header/Header';
import Header from './components/Header/Header';


function App() {
  return (
    <>
    <div className='header'>
    <Header />
    </div>

    <nav className='sidenav'>
      <ul>
        <li><Link to="/">1</Link><br></br></li> {" "}
        <li><Link to="/about">2</Link><br></br></li>
        <li><Link to="/about">3</Link><br></br></li>
      </ul>
    </nav>

    <Routes className='maincontent'>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About/>} />
    </Routes>
    </>




  );
}

export default App;
